import{_ as o,r as a,o as i,c as r,b as e,d as t,e as n,a as d}from"./app-2a089349.js";const c={},l=d(`<h1 id="stripe-shortcodes" tabindex="-1"><a class="header-anchor" href="#stripe-shortcodes" aria-hidden="true">#</a> Stripe Shortcodes</h1><p>Shortcodes in plugins serve to dynamically display content, extend functionality, customize features, integrate with other plugins or themes, and simplify complex tasks by allowing users to easily insert specific plugin features into their website content with minimal coding knowledge. As such, here are the Stripe shortcodes to simplify the integration of Stripe into your site.</p><h2 id="stripe-customer-portal-shortcode" tabindex="-1"><a class="header-anchor" href="#stripe-customer-portal-shortcode" aria-hidden="true">#</a> Stripe Customer Portal Shortcode</h2><p>Customers need to have the ability to manage their subscription plans. This shortcode creates a button that redirects customers to the external page of the Stripe Customer Portal to manage subscriptions. A user must be logged in for the redirection to work.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_customer_portal]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65bace3f7507a5314cbc0cf1/file-8ErFDhlRvD.png" alt=""></p><hr><h2 id="stripe-order-details-shortcode" tabindex="-1"><a class="header-anchor" href="#stripe-order-details-shortcode" aria-hidden="true">#</a> Stripe Order Details Shortcode</h2><p>This shortcode displays the order details, billing information, and subscription status for the customer. It allows them to review the information they&#39;ve provided. The order details will be displayed only when the user has completed the Stripe checkout process from the Stripe checkout page.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_checkout_order_details]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65bacf19ed989b06acd56722/file-atrbImGjh9.png" alt=""></p><hr><h2 id="stripe-checkout-shortcode" tabindex="-1"><a class="header-anchor" href="#stripe-checkout-shortcode" aria-hidden="true">#</a> Stripe Checkout Shortcode</h2><p>Customers need a way to subscribe to your site and access restricted pages and content based on the role assigned to them. With the Stripe module&#39;s shortcode, you can create Subscribe buttons so that customers can select them and proceed to the Stripe Checkout page for payment, and then assign roles based on the Subscription events.</p><p>The following example shortcode generates a button for customers to check out and subscribe. A user must be logged in for the redirection to work.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_checkout label=&quot;Annual VIP Membership – $ 299.99/year&quot; id=&quot;38&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65bacd1ca7493b27a932f870/file-m4YveRVF20.png" alt=""></p><h4 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a> ---</h4><h2 id="stripe-show-content-shortcode" tabindex="-1"><a class="header-anchor" href="#stripe-show-content-shortcode" aria-hidden="true">#</a> Stripe Show Content Shortcode</h2><p>Shortcodes to Display Active and Inactive Subscription Content or Messages</p><p>The shortcodes below allow you to display specific content or messages for users with active and inactive subscriptions:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_show_content] content [/ultimatemember_stripe_show_content]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>The default of this shortcode displays the content within the shortcode to users with an active subscription.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c12e62feff244b88aaeb82/file-q74W7Iji4A.png" alt=""></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c12e89fbf3330265919fad/file-DcTOhXNkLt.png" alt=""></p><p>It&#39;s important to note that if UM Content Restrictions are not enabled, it&#39;s recommended to use these shortcodes. This ensures a seamless and effective display of content based on the specified plans or prices.If you want to display or show specific content for active and inactive users in a single post or page, you need to add the following attributes in the shortcode:</p><h4 id="for-active-subscription" tabindex="-1"><a class="header-anchor" href="#for-active-subscription" aria-hidden="true">#</a> For active subscription</h4><p>Add this attribute <code>show_for=&quot;active&quot;</code> in the shortcode as shown in the example below to show the content for active users.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_show_content show_for=&quot;active&quot;]  

Hello active Members 

[/ultimatemember_stripe_show_content]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="for-inactivate-subscription" tabindex="-1"><a class="header-anchor" href="#for-inactivate-subscription" aria-hidden="true">#</a> For inactivate subscription</h4><p>Add this attribute <code>show_for=&quot;inactive&quot;</code> in the shortcode as shown in the example below to show the content for the inactive users.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_show_content show_for=&quot;inactive&quot;]    

Hello inactive Members  

[/ultimatemember_stripe_show_content]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Sample Usage:</strong></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c1e5b6fbf3330265919ff0/file-4b0aix5r7B.png" alt=""></p><p>When utilizing the provided shortcode above, you can enhance its functionality by integrating it with attributes <strong>Prices</strong> and <strong>Plans</strong>, separating them with a comma. In instances where both plans and prices are configured, the content will be visible only if a member possesses any of the plans or prices specified in the attributes.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_show_content show_for=&quot;active&quot; plans=&quot;123,456,789&quot; prices=&quot;165&quot;]

Hello Active Members by Plans/Prices

[/ultimatemember_stripe_show_content]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Sample Usage:</strong></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c1f365fbf3330265919ff6/file-gOSqLZTVdK.png" alt=""></p><p>If you have enabled <strong>Restrict Access by Stripe Plans</strong> and <strong>Active Subscription only</strong> in the <strong>Ultimate Member: Content Restriction</strong>, it&#39;s recommended to add the <code>template=1</code> attribute in the show content shortcode.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c23515fbf333026591a037/file-bFm3t6e3um.png" alt=""></p><p>This shortcode can also be integrated into PHP code, such as within a template or widget.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ultimatemember_stripe_show_content template=1]  content  [/ultimatemember_stripe_show_content]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c23428ffa21909875f08c8/file-rruXzrWVE7.png" alt=""></p><p>When the attribute is used, the filter to be applied is the <strong>&#39;Active Subscription only&#39;</strong>. If you have not selected any plans or prices from the <strong>&#39;Select Stripe Plans/Prices to allow access to this post&#39;</strong> option, the content is displayed and become accessible for users with active subscription. While users with inactive subscription might see any of the following messages. These notices or messages are intended exclusively for use with UM Content Restrictions &gt; Restrict Access by Stripe Plans&gt; Active Subscription only.</p><ol><li>&quot;Your current subscription plan does not provide access to this {post type/taxonomy name}. Please upgrade or subscribe to a different plan to view this <code>{post type/taxonomy name}</code>&quot;</li><li>&quot;Your current subscription plan is not allowed to access this {post type/taxonomy name}. Please upgrade or subscribe to a different plan to view this <code>{post type/taxonomy name}</code>.&quot;</li></ol><p><code>{post type/taxonomy name}</code> will be replaced automatically. If an archive page is restricted, it will be replaced with &quot;Please upgrade or subscribe to a different plan to view this category &quot; etc.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c23221feff244b88aaec06/file-aAl795aTLh.png" alt=""></p><p>If you&#39;ve chosen a Stripe plan or prices from the <strong>&#39;Select Stripe Plans/Prices to allow access to this post&#39;</strong> option, only users who have subscribed to the plan or purchased the prices will be able to view the content. The logic operates on an OR basis, meaning if a plan is not selected but prices are, users who have purchased the price will still have access to the content, and vice versa.</p><h4 id="list-of-shortcode-attributes" tabindex="-1"><a class="header-anchor" href="#list-of-shortcode-attributes" aria-hidden="true">#</a> List of shortcode attributes:</h4><table><thead><tr><th><strong>Attributes</strong></th><th><strong>Description &amp; Example</strong></th></tr></thead><tbody><tr><td><strong>label</strong></td><td>This attribute is required and is displayed on a page. e.g. label = <strong>&quot;CAD 3.00 / month&quot;</strong> <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6475df6867106052aab4ccf1/file-52z4Q9PXLF.png" alt=""></td></tr><tr><td><strong>id</strong></td><td>The Stripe Plan ID has been generated in wp-admin &gt; Ultimate Member &gt; Stripe Plans &gt; Add or Edit a Plan. When you create a Stripe plan, the shortcode will be displayed in the Stripe plan settings. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/651dbb29ed8c6d2f1cffdf26/file-IVhGzqfqP9.png" alt=""></td></tr><tr><td><strong>type</strong></td><td>- <strong>button</strong> - Shows a button element - <strong>link</strong> - Shows anchor HTML element - <strong>url</strong> - Shows a URL string <strong>Note:</strong> When a user is already subscribed to a plan, this text will show: <code>You&#39;re already subscribed </code> To modify the text, you can use this filter hook: <code>&lt;?php add_filter(&quot;umm_stripe_already_subscribed_text&quot;, function( $text ) { return esc_attr( &quot;You&#39;re subscribed to a plan!&quot; ); }); ?&gt; </code></td></tr><tr><td><strong>class</strong></td><td>Add custom classes to the button or anchor element. <code>[ultimatemember_stripe_customer_portal type=&quot;link&quot; label=&quot;customer portal&quot;]</code></td></tr><tr><td><strong>plans</strong></td><td>This attribute is added in the shortcode [ultimatemember_stripe_show_content] to determine the display of specific content or messages tailored to users with either an active or inactive subscription, depending on the specified <strong>plan</strong>.</td></tr><tr><td><strong>prices</strong></td><td>This attribute is added in the shortcode [ultimatemember_stripe_show_content] to determine the display of specific content or messages tailored to users with either an active or inactive subscription, depending on the specified <strong>prices</strong>.</td></tr><tr><td><strong>payment_method_types</strong></td><td>This attribute overrides the payment method type on the Stripe checkout page. - Default value( when the attribute is not added to the shortcode): <code>card</code> - This can have multiple attribute values separated by a comma. e.g. <code>card,alipay,grab</code></td></tr></tbody></table><h4 id="a-list-of-valid-payment-method-types-includes" tabindex="-1"><a class="header-anchor" href="#a-list-of-valid-payment-method-types-includes" aria-hidden="true">#</a> A list of valid payment method types includes:</h4><table><thead><tr><th>acss_debit</th><th>affirm</th><th>afterpay_clearpay</th><th>atdpay</th><th>au_becs_debit</th></tr></thead><tbody><tr><td>bacs_debit</td><td>bancontact</td><td>btdk</td><td>boleto</td><td>card</td></tr><tr><td>card_present</td><td>cashapp</td><td>eps</td><td>fpx</td><td>giropay</td></tr><tr><td>grabpay</td><td>ideal</td><td>klarna</td><td>konbini</td><td>tdnk</td></tr><tr><td>oxxo</td><td>p24</td><td>paynow</td><td>pix</td><td>promptpay</td></tr><tr><td>sepa_debit</td><td>sofort</td><td>us_bank_account</td><td>wechat_pay</td><td>zip</td></tr></tbody></table>`,52),h=e("strong",null,"Note:",-1),p={href:"https://dashboard.stripe.com/settings/payment_methods",target:"_blank",rel:"noopener noreferrer"},u=e("strong",null,"payment method settings.",-1),m=e("hr",null,null,-1),b=e("p",null,[e("strong",null,[t("NEXT: "),e("a",{href:"/docs-v3/um-stripe/article/1610-stripe---test-your-integration"},"Test Your Integration")])],-1);function g(f,v){const s=a("ExternalLinkIcon");return i(),r("div",null,[l,e("blockquote",null,[e("p",null,[h,t(" Each payment method type has to be enabled and configured in the Stripe "),e("a",p,[u,n(s)])])]),m,b])}const y=o(c,[["render",g],["__file","1616-stripe-shortcodes-reference.html.vue"]]);export{y as default};
